      const idx = tabs.indexOf(ctx.focusedTab);
      if (event2 === "NEXT")
        return { focusedTab: tabs[(idx + 1) % tabs.length] };
      if (event2 === "PREV")
        return { focusedTab: tabs[(idx - 1 + tabs.length) % tabs.length] };
