// website/src/utils/componentCategories.ts
var SLUG_TO_GROUP = {
  layout: "layout",
  forms: "forms",
  "data-display": "data-display",
  overlays: "overlays"
};
function getComponentsByCategory() {
  const componentsRoute = routes.find((r) => r.path === "/components");
  if (!componentsRoute?.children)
    return [];
  const groups = [];
  for (const sublevel of componentsRoute.children) {
    const slug = sublevel.path.split("/").pop() ?? "";
    const key2 = SLUG_TO_GROUP[slug];
    if (!key2 || !sublevel.children)
      continue;
    const subgroups = sublevel.children.filter((group) => group.children && group.children.length > 0).map((group) => ({
      label: group.label,
      description: group.description,
      routes: group.children ?? []
    }));
    if (subgroups.length === 0) {
      subgroups.push({
        label: sublevel.label,
        description: sublevel.description,
        routes: sublevel.children
      });
    }
    groups.push({
      key: key2,
      label: sublevel.label,
      description: sublevel.description,
      subgroups
    });
  }
  return groups;
}

