class SiguiToast extends SiguiElement {
  static observedAttributes = ["open", "duration"];
  _timer = null;
  static contract = Object.freeze({
    aria: { role: "status" }
  });
  connectedCallback() {
    super.connectedCallback();
    markComponent(this, "toast");
    setupMachine(this, toastMachine, "toastMachine");
    this._sync();
  }
  disconnectedCallback() {
    if (this._timer)
      clearTimeout(this._timer);
    cleanupMachine(this);
    super.disconnectedCallback();
  }
  attributeChangedCallback() {
    this._sync();
  }
  _sync() {
    const m = getMachine(this);
    if (!m)
      return;
    if (isOpenAttrTruthy(this)) {
      m.send("SHOW");
      if (m.state === "entering")
        m.send("ANIMATION_END");
      if (this._timer)
        clearTimeout(this._timer);
      const duration = Number(this.getAttribute("duration") || "5000");
      this._timer = setTimeout(() => {
        const m2 = getMachine(this);
        m2?.send("TIMEOUT");
        if (m2?.state === "exiting")
          m2.send("ANIMATION_END");
        this.removeAttribute("open");
      }, Number.isFinite(duration) && duration > 0 ? duration : 5000);
    }
  }
}

