// packages/components/src/index.js
function defineSiguiComponents(options = {}) {
  configureSiguiFeatures(options.featureFlags);
  if (typeof customElements === "undefined")
    return [];
  const tagPrefix = options.tagPrefix ?? "sg";
  const force = options.force === true;
  const defined = [];
  const definitions = { ...COMPONENT_DEFINITIONS, ...INTERACTIVE_COMPONENT_DEFINITIONS };
  for (const [key2, componentClass] of Object.entries(definitions)) {
    const tagName = `${tagPrefix}-${key2}`;
    if (customElements.get(tagName) && !force)
      continue;
    if (!customElements.get(tagName)) {
      customElements.define(tagName, componentClass);
    }
    defined.push(tagName);
  }
  return defined;
}

